fn juez_validar(graph: &mut eden_garm::HyperGraph, ids: RuntimeNodeIds, query: &str) -> String { let pack = Self::context_pack(graph, ids, query, 2, 5); let evidence = pack.path_explanations.len() + pack.kg_hits.len() + pack.memory_facts.len(); let verdict = if evidence >= 4 { "sostenido" } else if evidence >= 1 { "plausible-no-endurecer" } else { "sin-evidencia" }; let mut out = format!( "[JUEZ-EXTERNO] consulta='{}' verdict={} evidence={}
", query, verdict, evidence ); for path in pack.path_explanations.iter().take(3) { out.push_str(&format!("- kg: {}
", path)); } for (hit, score) in pack.kg_hits.iter().take(3) { out.push_str(&format!("- retrieval: {} ({:.2})
", hit, score)); } out.push
